def calculate_bmi(weight_kg, height_m):
    """Calculate BMI: weight (kg) / height (m) squared, rounded to 1 decimal."""
    return round(weight_kg / (height_m ** 2), 1)


def categorize_bmi(bmi):
    """Return BMI category: 'underweight', 'normal', 'overweight', or 'obese'."""
    if bmi < 18.5:
        return "underweight"
    elif bmi < 25.0:
        return "normal"
    elif bmi < 30.0:
        return "overweight"
    else:
        return "obese"


def is_valid_email(email):
    """Return True if email contains '@' and at least one '.' after the '@'."""
    if "@" not in email:
        return False
    at_index = email.index("@")
    return "." in email[at_index:]


def format_percentage(value, decimals=1):
    """Format a decimal value as a percentage string, e.g., 0.455 → '45.5%'."""
    return f"{value * 100:.{decimals}f}%"
